// newCLITokenMutation creates new mutation for the CLIToken entity.
func newCLITokenMutation(c config, op Op, opts ...clitokenOption) *CLITokenMutation {
	m := &CLITokenMutation{
		config:        c,
		op:            op,
		typ:           TypeCLIToken,
		clearedFields: make(map[string]struct{}),
	}
	for _, opt := range opts {
		opt(m)
	}
	return m
}

// withCLITokenID sets the ID field of the mutation.
func withCLITokenID(id uuid.UUID) clitokenOption {
	return func(m *CLITokenMutation) {
		var (
			err   error
			once  sync.Once
			value *CLIToken
		)
		m.oldValue = func(ctx context.Context) (*CLIToken, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().CLIToken.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

// withCLIToken sets the old CLIToken of the mutation.
func withCLIToken(node *CLIToken) clitokenOption {
	return func(m *CLITokenMutation) {
		m.oldValue = func(context.Context) (*CLIToken, error) {
			return node, nil
		}
		m.id = &node.ID
	}
}

